-- PROBLEMA 1: VIVO FIXO como entrada (id 90125, R$29.621 - saldo acumulado lido como receita)
-- Corrigir: mudar para expense (é uma conta de telefone)
UPDATE transactions SET type = 'expense' WHERE id = 90125 AND userId = 1;

-- PROBLEMA 2: PIX MYRNA duplicado (id 60604 - expense do Excel, já existe como transfer do Banco 301 id 90144)
-- Deletar o duplicado do Excel que está como expense
DELETE FROM transactions WHERE id = 60604 AND userId = 1;

-- PROBLEMA 3: Outros Vida fevereiro - os R$20k e R$12,5k são transferências internas (PJ→PF), não despesas
-- Corrigir tipo para transfer
UPDATE transactions SET type = 'transfer', description = 'PIX Myrna múltiplos (Transf interna PJ→PF)' 
WHERE id = 60107 AND userId = 1;

UPDATE transactions SET type = 'transfer', description = 'PIX Myrna múltiplos (Transf interna PJ→PF)'
WHERE id = 60106 AND userId = 1;

